INSERT INTO questions (level, difficulty, type, topic, question_text, options, correct_answer, explanation, study_tip, time_limit_seconds) VALUES
('A2',2,'multiple_choice','past_simple','They ___ a new house last year.','["bought", "buyed", "buy", "buying"]','bought','Irregular past of buy.','buy -> bought.',60),
('A2',2,'multiple_choice','past_simple','I ___ her at the party.','["saw", "seen", "seed", "see"]','saw','Irregular past of see.','see -> saw -> seen.',60),
('A2',2,'multiple_choice','present_continuous','She ___ for her keys now.','["is looking", "looks", "look", "looked"]','is looking','Action in progress.','look for = search.',60),
('A2',2,'multiple_choice','going_to','We ___ travel to Spain in July.','["are going to", "will to", "going", "go to"]','are going to','Future plans.','be going to for plans.',60),
('A2',2,'multiple_choice','comparatives','Math is ___ difficult than art.','["more", "most", "many", "much"]','more','difficult = long adjective.','more + long adjective.',60),
('A2',2,'multiple_choice','superlatives','The Amazon is the ___ river.','["longest", "longer", "more long", "most long"]','longest','Short adj + est.','long -> longest.',60),
('A2',2,'multiple_choice','past_continuous','While I ___, the phone rang.','["was reading", "read", "reads", "reading"]','was reading','Background action.','was/were + -ing for background.',60),
('A2',2,'multiple_choice','past_continuous','What ___ you doing at 5 p.m.?','["were", "was", "did", "are"]','were','you + were.','you/we/they + were.',60),
('A2',2,'multiple_choice','will','Don’t worry. I ___ help you.','["will", "am going to", "going", "would"]','will','Spontaneous decision.','will = offer/decision now.',60),
('A2',2,'multiple_choice','must_should','You ___ park here. It is forbidden.','["must not", "should not", "don’t must", "can not to"]','must not','Prohibition = must not.','must not = prohibition.',60),
('A2',2,'multiple_choice','present_perfect_intro','I ___ just finished my work.','["have", "has", "had", "am"]','have','Present perfect with just.','have/has + just + participle.',60),
('A2',2,'multiple_choice','present_perfect_intro','She ___ lost her phone.','["has", "have", "had", "is"]','has','she + has.','has for 3rd person singular.',60),
('A2',2,'multiple_choice','connectors','I was hungry ___ I made a sandwich.','["so", "but", "because", "or"]','so','Cause-result: so.','so = as a result.',60),
('A2',2,'multiple_choice','connectors','She stayed home ___ she was sick.','["because", "so", "but", "and"]','because','Reason: because.','because introduces reason.',60),
('A2',2,'multiple_choice','adverbs','He runs very ___.','["quickly", "quick", "quicker", "quickness"]','quickly','Adverb modifies verb.','adjective + ly.',60),
('A2',2,'multiple_choice','adverbs','She sings ___.','["well", "good", "goodly", "better"]','well','good -> well (irregular adverb).','well = adverb of good.',60),
('A2',2,'multiple_choice','countable_uncountable','There is not ___ milk left.','["much", "many", "few", "a lot"]','much','Negative + uncountable + much.','much in negatives/questions.',60),
('A2',2,'multiple_choice','countable_uncountable','I need ___ information.','["some", "a", "an", "many"]','some','Uncountable + some.','some + uncountable.',60),
('A2',2,'multiple_choice','past_simple','He did not ___ me yesterday.','["call", "called", "calling", "calls"]','call','After did not use base verb.','did not + base verb.',60),
('A2',2,'multiple_choice','past_simple','Where ___ you go last weekend?','["did", "was", "were", "do"]','did','Past question with did.','did + subject + base.',60),
('A2',2,'multiple_choice','present_continuous','They ___ not working today.','["are", "is", "do", "does"]','are','they + are.','are + not + -ing.',60),
('A2',2,'multiple_choice','going_to','She ___ study medicine.','["is going to", "will going", "goes to", "going to"]','is going to','3rd person singular + going to.','is/am/are + going to + base.',60),
('A2',2,'multiple_choice','comparatives','Today is ___ than yesterday.','["hotter", "hoter", "more hot", "hottest"]','hotter','Double consonant + er.','CVC pattern: double + er.',60),
('A2',2,'multiple_choice','superlatives','Who is the ___ person you know?','["funniest", "most funny", "funnyest", "funier"]','funniest','y -> i + est.','y ending: y->i+est.',60),
('A2',2,'multiple_choice','past_continuous','They ___ football when it started to rain.','["were playing", "played", "are playing", "play"]','were playing','Interrupted ongoing action.','past continuous + past simple.',60),
('A2',2,'multiple_choice','will','I ___ be 30 next year.','["will", "am going", "go", "do"]','will','Future fact.','will for facts/predictions.',60),
('A2',2,'multiple_choice','must_should','You look tired. You ___ rest.','["should", "must", "can", "could"]','should','Advice.','should + base for advice.',60),
('A2',2,'multiple_choice','present_perfect_intro','___ you ever eaten sushi?','["Have", "Has", "Did", "Do"]','Have','you + have.','Have/Has + subject + participle.',60),
('A2',2,'multiple_choice','connectors','I was tired ___ I continued working.','["but", "so", "because", "and"]','but','Contrast.','but = however.',60),
('A2',2,'multiple_choice','countable_uncountable','How ___ sugar do you want?','["much", "many", "few", "lots"]','much','sugar = uncountable.','much + uncountable.',60),
('A2',2,'multiple_choice','adverbs','She always arrives ___.','["late", "lately", "later", "latest"]','late','late is adverb and adjective.','late = both; lately = recently.',60),
('A2',2,'multiple_choice','going_to','They are not ___ come.','["going to", "will", "going", "go to"]','going to','Negative form of going to.','are not going to + base.',60),
('A2',2,'essay','past_simple','Describe a memorable trip in 4 sentences.',NULL,'Last summer I went to the beach. I stayed in a hotel. I swam every day. I ate fresh seafood.','Use past simple.','irregular verbs: went, ate, swam.',120),
('A2',2,'essay','going_to','Describe 4 plans for next month.',NULL,'I am going to start a new course. I am going to visit my uncle. I am going to save money. I am going to read more books.','Use going to for plans.','concrete plans = going to.',120),
('A2',2,'essay','comparatives','Compare two hobbies (4 sentences).',NULL,'Reading is more relaxing than gaming. Gaming is more exciting than reading. Gaming is more expensive. Reading is easier to do anywhere.','Use more/than for long adj.','long adj: more + adj + than.',120),
('A2',2,'essay','past_continuous','Describe what was happening at a party (4 sentences).',NULL,'People were dancing. Some were eating. Kids were playing. The music was playing loudly.','Use past continuous.','was/were + ing.',120),
('A2',2,'essay','present_perfect_intro','Write 4 things you have done in your life.',NULL,'I have visited Spain. I have eaten Japanese food. I have climbed a mountain. I have learned two languages.','Use have/has + participle.','life experiences = present perfect.',120),
('A2',2,'essay','will','Write 4 predictions for next year.',NULL,'I will finish my studies. I will travel abroad. I will get a new job. I will buy a car.','Use will for predictions.','will + base verb.',120),
('A2',2,'essay','must_should','Give 4 pieces of advice to a new student.',NULL,'You should arrive early. You must bring your book. You should take notes. You must not use your phone in class.','Mix should/must.','should advice, must obligation.',120),
('A2',2,'essay','connectors','Write a short story with connectors (4 sentences).',NULL,'I was tired but I had to work. I made coffee because I needed energy. I worked hard so I finished early. Then I went home and slept.','Use but/so/because/and.','Link ideas clearly.',120),
('A2',3,'multiple_choice','past_simple','When I was a child, I ___ to play outside.','["used", "use", "using", "use to"]','used','used to + base.','used to = past habit.',60),
('A2',3,'multiple_choice','past_simple','She ___ the truth yesterday.','["told", "tell", "telled", "tolded"]','told','Irregular past.','tell -> told.',60),
('A2',3,'multiple_choice','present_perfect_intro','They ___ lived here since 2010.','["have", "has", "had", "are"]','have','Plural subject + have.','for/since + present perfect.',60),
('A2',3,'multiple_choice','present_perfect_intro','He ___ finished his project.','["has not", "have not", "did not", "is not"]','has not','3rd person singular negative.','has not = hasn’t.',60),
('A2',3,'multiple_choice','going_to','I am not ___ wait anymore.','["going to", "will to", "go to", "going"]','going to','Negative going to.','not going to + base.',60),
('A2',3,'multiple_choice','past_continuous','While she ___, he arrived.','["was cooking", "cooked", "cooks", "is cooking"]','was cooking','Background action in past.','while + past continuous.',60),
('A2',3,'multiple_choice','comparatives','This test is ___ than the last one.','["less difficult", "lesser difficult", "more less", "most less"]','less difficult','less + adj for comparison down.','less = opposite of more.',60),
('A2',3,'multiple_choice','superlatives','He is the ___ worker in the team.','["hardest", "most hard", "harder", "hardly"]','hardest','Short adj + est.','hard -> hardest.',60),
('A2',3,'multiple_choice','will','I promise I ___ call you later.','["will", "am going to", "going", "would"]','will','Promise = will.','will = promise/offer.',60),
('A2',3,'multiple_choice','must_should','You ___ be over 18 to drive.','["must", "should", "can", "may"]','must','Rule = must.','must for rules.',60),
('A2',3,'multiple_choice','connectors','She was late ___ of the traffic.','["because", "so", "but", "for"]','because','because of + noun.','because + clause, because of + noun.',60),
('A2',3,'multiple_choice','connectors','___ it was raining, we went out.','["Although", "Because", "So", "But"]','Although','Contrast at start.','although = even though.',60),
('A2',3,'multiple_choice','adverbs','He finished ___ easily.','["quite", "quiet", "quieter", "quietly"]','quite','quite = intensifier.','quite + adverb.',60),
('A2',3,'multiple_choice','adverbs','She almost ___ forgot my name.','["completely", "complete", "completion", "completeness"]','completely','Two adverbs.','almost + adverb.',60),
('A2',3,'multiple_choice','countable_uncountable','I do not have ___ time.','["enough", "many", "few", "lot"]','enough','enough + uncountable.','enough + noun.',60),
('A2',3,'multiple_choice','countable_uncountable','There are ___ of apples.','["lots", "a lot", "much", "many"]','lots','lots of + any noun.','lots of = a lot of.',60),
('A2',3,'multiple_choice','past_simple','They ___ married in 2020.','["got", "get", "gets", "getted"]','got','Irregular past of get.','get -> got.',60),
('A2',3,'multiple_choice','past_simple','She did not ___ the email.','["receive", "received", "receives", "receiving"]','receive','After did not use base.','did not + base.',60),
('A2',3,'multiple_choice','present_continuous','I ___ studying these days.','["am", "do", "have", "is"]','am','I + am.','I am + ing.',60),
('A2',3,'multiple_choice','going_to','What ___ they going to do?','["are", "is", "do", "have"]','are','Plural + are going to.','they are going to.',60),
('A2',3,'multiple_choice','comparatives','He is ___ older than his sister.','["much", "more", "very", "well"]','much','much + comparative for emphasis.','much/far + comparative.',60),
('A2',3,'multiple_choice','superlatives','Mount Everest is one of the ___ mountains.','["highest", "most high", "higher", "highly"]','highest','Short adj: est.','high -> highest.',60),
('A2',3,'multiple_choice','past_continuous','I was reading ___ you called.','["when", "while", "during", "since"]','when','when + past simple event.','while + ongoing, when + event.',60),
('A2',3,'multiple_choice','will','I think Brazil ___ win the cup.','["will", "is going to", "would", "might"]','will','Prediction with think.','I think + will.',60),
('A2',3,'multiple_choice','must_should','You ___ eat too much sugar.','["should not", "must not", "cannot", "will not"]','should not','Advice against.','should not = negative advice.',60),
('A2',3,'multiple_choice','present_perfect_intro','I ___ known her for 10 years.','["have", "has", "had", "having"]','have','I + have.','for + period.',60),
('A2',3,'multiple_choice','present_perfect_intro','She ___ lived there since June.','["has", "have", "had", "is"]','has','she + has.','since + point in time.',60),
('A2',3,'multiple_choice','connectors','I like both coffee ___ tea.','["and", "or", "but", "so"]','and','both...and.','both X and Y.',60),
('A2',3,'multiple_choice','connectors','We can eat pizza ___ pasta.','["or", "but", "so", "because"]','or','Choice: or.','or = alternative.',60),
('A2',3,'multiple_choice','adverbs','She works very ___.','["hard", "hardly", "harder", "hardest"]','hard','hard = adverb too.','hardly = almost not!',60),
('A2',3,'multiple_choice','countable_uncountable','There is ___ bread left.','["a little", "a few", "many", "several"]','a little','a little + uncountable.','a little = small amount uncountable.',60),
('A2',3,'multiple_choice','countable_uncountable','I have ___ friends here.','["a few", "a little", "much", "less"]','a few','a few + countable plural.','a few = small number countable.',60),
('A2',3,'essay','past_experience','Describe a memorable day in 4 sentences using past tenses.',NULL,'I was walking in the park when it started to rain. I ran to a cafe. I ordered a hot chocolate. I met an old friend there.','Mix past simple and continuous.','while/when + correct tense.',120),
('A2',3,'essay','future_plans','Write 4 sentences about your career plans.',NULL,'I am going to finish my degree next year. I will look for a job. I hope I will work abroad. I am going to save money.','Mix going to and will.','going to = plans, will = predictions.',120),
('A2',3,'essay','comparisons','Compare life in the city and countryside (4 sentences).',NULL,'The city is more exciting than the countryside. The countryside is quieter. Cities are more expensive. Life in the countryside is healthier.','Use comparatives and superlatives.','more/less, -er/-est.',120),
('A2',3,'essay','present_perfect_intro','Write 4 life experiences using ever/never.',NULL,'I have never been to Japan. I have eaten sushi. I have met a famous person once. I have never tried skydiving.','Use have/has + participle.','ever/never with present perfect.',120),
('A2',3,'essay','advice','Give advice to a friend moving abroad (4 sentences).',NULL,'You should learn the language. You must get insurance. You should not forget your documents. You should make local friends.','Use should/must.','should advice, must essentials.',120),
('A2',3,'essay','connectors','Write a paragraph about a difficult decision (4 sentences).',NULL,'I wanted to change jobs but I was afraid. Although the new job paid more, it was far away. I finally accepted because I needed a change. Now I am happy with my choice.','Use multiple connectors.','but/although/because.',120),
('A2',3,'essay','past_continuous','Describe a scene from last week (4 sentences).',NULL,'It was 7 pm and the sun was setting. People were walking home. Children were playing. I was enjoying the view.','Use past continuous for scene.','Set the scene with was/were + ing.',120),
('A2',3,'essay','predictions','Make 4 predictions about technology.',NULL,'Robots will do more jobs. Cars will drive themselves. People will use less cash. We will all have smart homes.','Use will for predictions.','will + base verb.',120),
('B1',1,'multiple_choice','present_perfect','I have lived here ___ 2015.','["since", "for", "from", "ago"]','since','since + point in time.','since + starting point.',60),
('B1',1,'multiple_choice','present_perfect','She has worked here ___ ten years.','["for", "since", "during", "ago"]','for','for + duration.','for + period of time.',60),
('B1',1,'multiple_choice','present_perfect','They ___ finished the project yet.','["have not", "did not", "do not", "had not"]','have not','yet + present perfect negative.','yet at end of negatives/questions.',60),
('B1',1,'multiple_choice','present_perfect','___ you ever visited London?','["Have", "Has", "Did", "Do"]','Have','Experience question.','Have/Has + ever + participle.',60),
('B1',1,'multiple_choice','first_conditional','If it rains, we ___ stay home.','["will", "would", "would have", "will have"]','will','1st conditional: if + present, will + base.','real future: if + present, will.',60),
('B1',1,'multiple_choice','first_conditional','If you ___ early, you will catch the bus.','["leave", "left", "leaves", "will leave"]','leave','if + present simple.','if-clause uses present simple.',60),
('B1',1,'multiple_choice','second_conditional','If I ___ rich, I would travel.','["were", "was", "am", "be"]','were','2nd conditional uses were for all.','If I were... (hypothetical).',60),
('B1',1,'multiple_choice','second_conditional','She would help if she ___ time.','["had", "has", "have", "will have"]','had','2nd conditional: past simple.','if + past simple, would + base.',60),
('B1',1,'multiple_choice','passive_voice','The book ___ by many people.','["is read", "reads", "read", "reading"]','is read','Present passive.','be + past participle.',60),
('B1',1,'multiple_choice','passive_voice','The letter was ___ yesterday.','["sent", "send", "sending", "sends"]','sent','Past passive.','was/were + participle.',60),
('B1',1,'multiple_choice','reported_speech','He said he ___ tired.','["was", "is", "be", "were"]','was','Present -> past in reported.','tense backshift.',60),
('B1',1,'multiple_choice','reported_speech','She told me she ___ come.','["would", "will", "can", "may"]','would','will -> would.','will becomes would.',60),
('B1',1,'multiple_choice','phrasal_verbs','Please ___ off your shoes.','["take", "make", "do", "put"]','take','take off = remove.','take off clothes/shoes.',60),
('B1',1,'multiple_choice','phrasal_verbs','I need to ___ up early.','["get", "take", "give", "stand"]','get','get up = leave bed.','get up in the morning.',60),
('B1',1,'multiple_choice','relative_clauses','The man ___ lives next door is nice.','["who", "which", "whose", "where"]','who','who for people.','who = for people.',60),
('B1',1,'multiple_choice','relative_clauses','The book ___ I bought is great.','["which", "who", "whose", "where"]','which','which for things.','which/that for things.',60),
('B1',1,'multiple_choice','modal_verbs','You ___ be tired after the trip.','["must", "can", "should", "would"]','must','deduction = must.','must = strong certainty.',60),
('B1',1,'multiple_choice','modal_verbs','It ___ rain later; bring an umbrella.','["might", "must", "can", "will"]','might','possibility = might.','might = possibility.',60),
('B1',1,'multiple_choice','linking_words','___, I passed the exam.','["Finally", "Final", "Ending", "Last"]','Finally','Sentence adverb.','Finally = at last.',60),
('B1',1,'multiple_choice','linking_words','I was tired. ___, I finished.','["However", "Because", "So", "Then"]','However','Contrast.','However starts a new idea with comma.',60),
('B1',1,'multiple_choice','present_perfect','He has ___ lived abroad.','["never", "ever", "since", "for"]','never','never + participle.','never = not once.',60),
('B1',1,'multiple_choice','first_conditional','If you study, you ___ pass.','["will", "would", "shall", "have"]','will','Real future.','will + base.',60),
('B1',1,'multiple_choice','second_conditional','I ___ travel if I had time.','["would", "will", "can", "do"]','would','Hypothetical.','would + base verb.',60),
('B1',1,'multiple_choice','passive_voice','English ___ all over the world.','["is spoken", "speaks", "spoken", "speaking"]','is spoken','Present simple passive.','is/are + participle.',60),
('B1',1,'multiple_choice','reported_speech','He said, "I am happy." -> He said he ___ happy.','["was", "is", "were", "be"]','was','Backshift.','am/is -> was, are -> were.',60),
('B1',1,'multiple_choice','phrasal_verbs','Can you ___ me up at 7?','["pick", "take", "give", "get"]','pick','pick up = collect.','pick up = collect someone.',60),
('B1',1,'multiple_choice','relative_clauses','That is the house ___ I was born.','["where", "which", "who", "when"]','where','where for places.','where = in which place.',60),
('B1',1,'multiple_choice','modal_verbs','You ___ smoke here, it is prohibited.','["must not", "do not have to", "should not", "might not"]','must not','Prohibition.','must not = prohibition.',60),
('B1',1,'multiple_choice','linking_words','I like tea. ___, I do not drink coffee.','["However", "Because", "So", "Although"]','However','Contrast between sentences.','However separates ideas.',60),
('B1',1,'multiple_choice','present_perfect','We ___ just arrived.','["have", "has", "are", "did"]','have','we + have + just + participle.','just = recently.',60),
('B1',1,'multiple_choice','first_conditional','Unless you hurry, you ___ be late.','["will", "would", "are", "have"]','will','unless = if not.','unless + present + will.',60),
('B1',1,'multiple_choice','second_conditional','What ___ you do if you won?','["would", "will", "do", "are"]','would','Question form 2nd conditional.','What would + subject + base.',60),
('B1',1,'essay','present_perfect','Write about your experiences (4 sentences with present perfect).',NULL,'I have traveled to five countries. I have never eaten frog legs. I have learned two languages. I have lived in three cities.','Use have/has + participle.','ever, never, yet, already.',120),
('B1',1,'essay','first_conditional','Write 4 first conditional sentences about tomorrow.',NULL,'If it is sunny, I will go to the beach. If I finish early, I will call you. If it rains, I will stay home. If I have time, I will cook dinner.','Use if + present, will.','real future conditions.',120),
('B1',1,'essay','second_conditional','Write 4 imaginary situations.',NULL,'If I had a million dollars, I would buy a house. If I were president, I would help the poor. If I could fly, I would travel the world. If I knew her number, I would call.','Use if + past, would + base.','Hypothetical/imaginary.',120),
('B1',1,'essay','passive_voice','Describe a process in 4 passive sentences.',NULL,'The coffee beans are picked. They are roasted carefully. They are ground into powder. The coffee is then served.','Use passive voice.','be + past participle.',120),
('B1',1,'essay','reported_speech','Rewrite 4 statements in reported speech.',NULL,'She said she was tired. He told me he would come. They said they had finished. She said she liked it.','Apply tense backshift.','is -> was, will -> would.',120),
('B1',1,'essay','phrasal_verbs','Write 4 sentences with phrasal verbs.',NULL,'I get up at 6 every day. Please turn off the lights. She looks after her sister. I ran into an old friend.','Use common phrasal verbs.','get up, turn off, look after, run into.',120),
('B1',1,'essay','modal_verbs','Write 4 sentences about rules and possibilities.',NULL,'You must wear a helmet. You may not enter here. It might rain tomorrow. You should try this.','Use various modals.','must, may, might, should.',120),
('B1',1,'essay','linking_words','Write a paragraph using at least 3 linking words (4 sentences).',NULL,'I wanted to go out; however, I was tired. Moreover, it was raining. Therefore, I stayed home. Finally, I read a book.','Use however, therefore, moreover.','formal linkers.',120),
('B1',2,'multiple_choice','present_perfect_continuous','I ___ studying for 2 hours.','["have been", "has been", "am", "had been"]','have been','Ongoing action.','have/has been + ing.',60),
('B1',2,'multiple_choice','present_perfect_continuous','She ___ working here since May.','["has been", "have been", "is", "was"]','has been','3rd person ongoing.','has been + ing.',60),
('B1',2,'multiple_choice','third_conditional','If I ___ known, I would have helped.','["had", "have", "would", "did"]','had','3rd conditional: had + participle.','if + past perfect, would have + participle.',60),
('B1',2,'multiple_choice','third_conditional','She ___ passed if she had studied.','["would have", "will have", "would", "had"]','would have','Unreal past.','would have + participle.',60),
('B1',2,'multiple_choice','passive_voice','The project ___ finished next month.','["will be", "will", "is", "has"]','will be','Future passive.','will be + participle.',60),
('B1',2,'multiple_choice','reported_speech','She asked me if I ___ her.','["knew", "know", "had known", "would know"]','knew','know -> knew in reported.','present -> past in reported questions.',60),
('B1',2,'multiple_choice','phrasal_verbs','I cannot ___ up with this noise.','["put", "make", "take", "stand"]','put','put up with = tolerate.','put up with = tolerate.',60),
('B1',2,'multiple_choice','phrasal_verbs','She ___ off the meeting.','["called", "made", "took", "put"]','called','call off = cancel.','call off = cancel.',60),
('B1',2,'multiple_choice','relative_clauses','This is the teacher ___ son plays football.','["whose", "who", "which", "that"]','whose','possession: whose.','whose = possessive relative.',60),
('B1',2,'multiple_choice','relative_clauses','2020 was the year ___ everything changed.','["when", "where", "which", "who"]','when','when for times.','when = in which time.',60),
('B1',2,'multiple_choice','modal_verbs','You ___ have told me earlier!','["should", "must", "will", "can"]','should','Past criticism.','should have + participle.',60),
('B1',2,'multiple_choice','modal_verbs','He ___ be at home; the lights are on.','["must", "can", "may not", "will"]','must','Strong deduction.','must = almost certain.',60),
('B1',2,'multiple_choice','linking_words','He is smart; ___, he is kind.','["moreover", "but", "because", "however"]','moreover','Addition.','moreover = in addition.',60),
('B1',2,'multiple_choice','linking_words','She studied hard; ___, she passed.','["therefore", "however", "but", "although"]','therefore','Consequence.','therefore = as a result.',60),
('B1',2,'multiple_choice','present_perfect','I have ___ been to Asia.','["never", "ever", "yet", "still"]','never','never + participle.','never = not ever.',60),
('B1',2,'multiple_choice','first_conditional','If you do not hurry, you ___ miss the train.','["will", "would", "are", "do"]','will','Real future consequence.','will + base verb.',60),
('B1',2,'multiple_choice','second_conditional','If I ___ you, I would accept.','["were", "was", "am", "be"]','were','Formal 2nd conditional.','If I were you...',60),
