('A1',3,'multiple_choice','verb_to_be','There ___ a problem with my computer.','["is", "are", "am", "be"]','is','Singular subject.','there is + singular noun.',60),
('A1',3,'multiple_choice','articles','I saw ___ interesting film yesterday.','["an", "a", "the", "-"]','an','interesting starts with vowel sound.','a/an by sound not letter.',60),
('A1',3,'multiple_choice','articles','My father is ___ engineer.','["an", "a", "the", "-"]','an','engineer = vowel sound.','Jobs: a/an + job.',60),
('A1',3,'multiple_choice','prepositions','He arrives ___ the airport at 5.','["at", "in", "on", "to"]','at','Places: at + specific point.','at + station/airport.',60),
('A1',3,'multiple_choice','prepositions','The keys are ___ my jacket.','["in", "on", "at", "by"]','in','Inside pocket = in.','Inside containers = in.',60),
('A1',3,'multiple_choice','present_simple','Does she ___ Japanese?','["speak", "speaks", "speaking", "spoke"]','speak','After does use base form.','does + subject + base.',60),
('A1',3,'multiple_choice','present_simple','They ___ not have a car.','["do", "does", "are", "is"]','do','they + do not.','Plural: do not.',60),
('A1',3,'multiple_choice','can','Why ___ you come to the party?','["cant", "cannot to", "dont can", "not can"]','cant','Questions with cant.','Why cant + subject.',60),
('A1',3,'multiple_choice','this_that','Whose jacket is ___?','["this", "these", "those", "is"]','this','Singular near.','Whose + noun + is/are + demonstrative.',60),
('A1',3,'multiple_choice','plural','One tooth, two ___.','["teeth", "tooths", "tooth", "toothes"]','teeth','Irregular plural.','tooth -> teeth.',60),
('A1',3,'multiple_choice','plural','One person, several ___.','["people", "persons", "peoples", "person"]','people','people is the normal plural.','person -> people.',60),
('A1',3,'multiple_choice','there_is_are','There ___ some apples on the table.','["are", "is", "have", "be"]','are','apples is plural.','some + plural + are.',60),
('A1',3,'multiple_choice','imperatives','___ late for the meeting.','["Dont be", "No be", "Not be", "Dont"]','Dont be','Negative imperative of be.','Dont be + adjective.',60),
('A1',3,'multiple_choice','numbers','The year 2025 is read as ___.','["twenty twenty-five", "two thousand twenty-five", "two zero two five", "twenty two five"]','twenty twenty-five','Years often split in pairs.','Post-2000 years: twenty + XX.',60),
('A1',3,'multiple_choice','colors','Mix red and yellow = ___.','["orange", "purple", "green", "pink"]','orange','Color mixing fact.','Red+yellow=orange.',60),
('A1',3,'multiple_choice','family','My brothers daughter is my ___.','["niece", "nephew", "cousin", "sister"]','niece','Brothers daughter = niece.','niece(f) / nephew(m).',60),
('A1',3,'multiple_choice','greetings','A formal way to say goodbye is ___.','["Goodbye", "Bye", "See ya", "Cya"]','Goodbye','Goodbye is formal.','Formal: Goodbye. Informal: Bye.',60),
('A1',3,'multiple_choice','verb_to_be','___ I late?','["Am", "Is", "Are", "Do"]','Am','Question with I uses Am.','Am I + adjective?',60),
('A1',3,'multiple_choice','verb_to_be','We ___ not ready.','["are", "is", "am", "be"]','are','We takes are.','we/you/they are.',60),
('A1',3,'multiple_choice','present_simple','He ___ to the gym twice a week.','["goes", "go", "going", "went"]','goes','Habit + 3rd person.','go -> goes (3rd person).',60),
('A1',3,'multiple_choice','present_simple','What time ___ the shop open?','["does", "do", "is", "are"]','does','the shop = singular.','does + singular subject.',60),
('A1',3,'multiple_choice','prepositions','We meet ___ Christmas Eve.','["on", "in", "at", "by"]','on','Specific days use on.','on + specific day/date.',60),
('A1',3,'multiple_choice','prepositions','The party is ___ Friday night.','["on", "in", "at", "by"]','on','Days of week use on.','on + weekday.',60),
('A1',3,'multiple_choice','articles','___ dog is barking.','["The", "A", "An", "-"]','The','Specific dog.','the = specific item.',60),
('A1',3,'multiple_choice','articles','I need ___ umbrella.','["an", "a", "the", "-"]','an','umbrella = vowel sound.','an + vowel sound.',60),
('A1',3,'multiple_choice','can','___ he speak three languages?','["Can", "Does can", "Is can", "Do can"]','Can','Modal questions invert.','Can + subject + base?',60),
('A1',3,'multiple_choice','this_that','Are ___ your shoes?','["these", "this", "that", "is"]','these','Plural near.','these = plural near.',60),
('A1',3,'multiple_choice','family','My wifes brother is my ___.','["brother-in-law", "cousin", "son-in-law", "uncle"]','brother-in-law','In-law for spouses family.','Spouses sibling = in-law.',60),
('A1',3,'multiple_choice','there_is_are','___ there any sugar?','["Is", "Are", "Have", "Do"]','Is','sugar = uncountable.','Uncountables use is.',60),
('A1',3,'multiple_choice','imperatives','Always ___ your seatbelt.','["wear", "wears", "wearing", "wore"]','wear','Imperative = base verb.','Always/Never + base verb.',60),
('A1',3,'multiple_choice','numbers','Half of 50 is ___.','["twenty-five", "twenty five", "fifteen", "thirty five"]','twenty-five','50/2=25, hyphenated.','Compound numbers with hyphen.',60),
('A1',3,'essay','daily_routine','Describe a typical day in 4 sentences.',NULL,'I wake up at 7. I work from 9 to 5. I have dinner at 7. I sleep at 11.','Use time expressions and present simple.','from X to Y, at + time.',120),
('A1',3,'essay','family','Write about 2 family members (4 sentences).',NULL,'My mother is a doctor. She is 50. My brother is a student. He is 20.','Use is + job/age.','Describe with is/are.',120),
('A1',3,'essay','can','Describe 4 things you can or cannot do.',NULL,'I can cook Italian food. I cant play piano. I can drive. I cant swim well.','Use can/cannot + base.','Vary positive and negative.',120),
('A1',3,'essay','prepositions','Describe your neighborhood (4 sentences).',NULL,'There is a park near my house. The supermarket is on the corner. My school is in front of the bank. The bus stop is next to the cafe.','Use prepositions of place.','near, next to, in front of, on.',120),
('A1',3,'essay','present_simple','Describe your hobbies (4 sentences).',NULL,'I play football on Saturdays. I read books at night. I watch movies on Sundays. I dont play video games.','Mix positive and negative.','dont + base for negative.',120),
('A1',3,'essay','greetings','Write a dialogue with 4 lines greeting a friend.',NULL,'Hi Sam! How are you today? I am great, thanks. And you?','Use common greetings.','How are you? Fine thanks, and you?',120),
('A1',3,'essay','there_is_are','Describe a classroom (4 sentences).',NULL,'There is a board. There are twenty chairs. There is a teacher. There are many books.','Alternate is/are.','Singular vs plural count.',120),
('A1',3,'essay','colors','Describe your clothes today (4 sentences).',NULL,'My shirt is white. My pants are blue. My shoes are black. My jacket is gray.','Use subject + be + color.','singular is, plural are.',120),
('A2',1,'multiple_choice','past_simple','Yesterday I ___ to the cinema.','["went", "go", "goes", "gone"]','went','Irregular past of go.','go -> went.',60),
('A2',1,'multiple_choice','past_simple','She ___ her homework last night.','["finished", "finish", "finishes", "finishing"]','finished','Regular past with -ed.','regular verbs + -ed.',60),
('A2',1,'multiple_choice','past_simple','They ___ not come to the party.','["did", "do", "was", "were"]','did','Negative past: did not.','did + not + base verb.',60),
('A2',1,'multiple_choice','past_simple','___ you see the movie?','["Did", "Do", "Was", "Were"]','Did','Past question: Did + subject.','Did + subject + base?',60),
('A2',1,'multiple_choice','present_continuous','Look! It ___ now.','["is raining", "rains", "rain", "rained"]','is raining','Action happening now.','be + verb-ing.',60),
('A2',1,'multiple_choice','present_continuous','We ___ dinner at the moment.','["are having", "have", "has", "having"]','are having','Now action, plural subject.','are + verb-ing.',60),
('A2',1,'multiple_choice','going_to','Tomorrow I ___ visit my aunt.','["am going to", "will going", "go", "going"]','am going to','Future plan = be going to.','planned future = going to.',60),
('A2',1,'multiple_choice','going_to','What ___ do tonight?','["are you going to", "you will", "do you going", "will you go"]','are you going to','Question form of going to.','be + subject + going to.',60),
('A2',1,'multiple_choice','comparatives','A car is ___ than a bike.','["faster", "fast", "fastest", "more fast"]','faster','Short adjective + -er.','short adj + er + than.',60),
('A2',1,'multiple_choice','comparatives','This book is ___ interesting than that one.','["more", "most", "much", "very"]','more','Long adjective uses more.','long adj: more + adj.',60),
('A2',1,'multiple_choice','superlatives','He is the ___ student in class.','["tallest", "taller", "tall", "most tall"]','tallest','Short adj + -est.','the + adj+est.',60),
('A2',1,'multiple_choice','superlatives','It is the ___ beautiful city.','["most", "more", "very", "much"]','most','Long adj: the most + adj.','the most + long adj.',60),
('A2',1,'multiple_choice','adverbs','She sings ___.','["beautifully", "beautiful", "more beautiful", "beauty"]','beautifully','Adverbs modify verbs.','adj + -ly = adverb.',60),
('A2',1,'multiple_choice','adverbs','He drives ___.','["carefully", "careful", "care", "carefuly"]','carefully','adj+ly.','careful -> carefully.',60),
('A2',1,'multiple_choice','will','I think it ___ rain tomorrow.','["will", "going", "is", "would"]','will','Prediction = will.','will + base verb.',60),
('A2',1,'multiple_choice','must_should','You ___ drink water every day.','["should", "shoulds", "musts", "oughts"]','should','Advice = should.','should + base.',60),
('A2',1,'multiple_choice','must_should','Drivers ___ stop at red lights.','["must", "should", "may", "can"]','must','Obligation = must.','must = strong obligation.',60),
('A2',1,'multiple_choice','past_continuous','I ___ TV when you called.','["was watching", "watched", "watch", "am watching"]','was watching','Past continuous for interrupted action.','was/were + verb-ing.',60),
('A2',1,'multiple_choice','past_continuous','They ___ at 8 p.m. yesterday.','["were sleeping", "slept", "sleep", "was sleeping"]','were sleeping','Plural past continuous.','they were + verb-ing.',60),
('A2',1,'multiple_choice','present_perfect_intro','I ___ never been to Paris.','["have", "has", "had", "am"]','have','I + have + past participle.','have/has + participle.',60),
('A2',1,'multiple_choice','present_perfect_intro','She ___ seen that movie.','["has", "have", "had", "is"]','has','Third person singular: has.','he/she/it + has.',60),
('A2',1,'multiple_choice','connectors','I like coffee ___ I dont like tea.','["but", "and", "or", "so"]','but','Contrast = but.','but shows contrast.',60),
('A2',1,'multiple_choice','connectors','It was late ___ we went home.','["so", "but", "or", "because"]','so','Result = so.','so shows result.',60),
('A2',1,'multiple_choice','countable_uncountable','How ___ water do you drink?','["much", "many", "some", "any"]','much','Uncountable uses much.','much + uncountable.',60),
('A2',1,'multiple_choice','countable_uncountable','How ___ books do you have?','["many", "much", "any", "some"]','many','Countable plural uses many.','many + countable plural.',60),
('A2',1,'multiple_choice','past_simple','Where ___ you yesterday?','["were", "was", "did", "are"]','were','you + were.','was (I/he/she/it), were (you/we/they).',60),
('A2',1,'multiple_choice','past_simple','He ___ at home last night.','["was", "were", "is", "did"]','was','Singular subject.','he/she/it was.',60),
('A2',1,'multiple_choice','present_continuous','Why ___ you crying?','["are", "do", "is", "does"]','are','you + are.','Question: be + subject + -ing.',60),
('A2',1,'multiple_choice','going_to','Look at those clouds! It ___ rain.','["is going to", "will", "rains", "rained"]','is going to','Evidence-based prediction.','See evidence -> going to.',60),
('A2',1,'multiple_choice','comparatives','My bag is ___ than yours.','["heavier", "heavy", "heaviest", "more heavy"]','heavier','y -> ier.','adj ending in y: y->i+er.',60),
('A2',1,'multiple_choice','superlatives','This is the ___ day of my life.','["best", "better", "goodest", "most good"]','best','good -> best (irregular).','good/better/best.',60),
('A2',1,'multiple_choice','adverbs','He speaks English ___.','["fluently", "fluent", "fluence", "fluents"]','fluently','Adverb form.','fluent -> fluently.',60),
('A2',1,'essay','past_simple','Write about what you did last weekend (3 sentences).',NULL,'I went to the park. I met my friends. We played football.','Use past simple verbs.','go->went, meet->met, play->played.',120),
('A2',1,'essay','going_to','Write 3 sentences about your plans for next week.',NULL,'I am going to visit my grandmother. I am going to study English. I am going to cook pasta.','Use be going to + base verb.','be going to for plans.',120),
('A2',1,'essay','comparatives','Compare two cities you know (3 sentences).',NULL,'São Paulo is bigger than Rio. Rio is more beautiful than São Paulo. São Paulo is noisier than Rio.','Use comparatives.','short+er, long: more+adj.',120),
('A2',1,'essay','present_continuous','Describe what people around you are doing (3 sentences).',NULL,'My sister is reading a book. My dog is sleeping. My neighbor is washing his car.','Use present continuous.','be + -ing.',120),
('A2',1,'essay','must_should','Give 3 pieces of health advice.',NULL,'You should exercise every day. You must not smoke. You should eat vegetables.','Use should/must.','should for advice, must for strong rules.',120),
('A2',1,'essay','past_continuous','Describe what you were doing yesterday at 8 p.m. (3 sentences).',NULL,'I was watching TV at 8. My brother was studying. My mom was cooking dinner.','Use past continuous.','was/were + -ing.',120),
('A2',1,'essay','will','Make 3 predictions about the future.',NULL,'Cars will fly one day. People will live longer. We will travel to Mars.','Use will + base.','will for predictions.',120),
('A2',1,'essay','connectors','Write 3 sentences using but, so, because.',NULL,'I wanted to go out but it rained. It was late so I stayed home. I was tired because I worked all day.','Use linking words.','but contrast, so result, because reason.',120)
